do {
	rc = ldap_sasl_interactive_bind( ld, binddn, sasl_mech,
		sctrlsp, NULL, sasl_flags, lutil_sasl_interact, defaults,
		result, &rmech, &msgid );

	if ( rc != LDAP_SASL_BIND_IN_PROGRESS )
		break;

